```class Solution:
    def reverseOnlyLetters(self, s: str) -> str:
        letters = []
        for c in s:
            if c.isalpha():
                letters.append(c)
        result = list(s)
        left, right = 0, len(letters) - 1
        for i in range(len(s)):
            if not s[i].isalpha():
                continue
            if left <= right:
                result[i] = letters[left]
                left += 1
            else:
                break
        left, right = 0, len(letters) - 1
        for i in range(len(s) - 1, -1, -1):
            if not s[i].isalpha():
                continue
            if left <= right:
                result[i] = letters[right]
                right -= 1
            else:
                break
        return ''.join(result)
